#include<bits/stdc++.h>
using namespace std;
struct node {
	node *left;
	node *right;
	int x;
} a[100005];
int k[100005], p[100005];
bool v[100005];
int main() {
	a[0].x = 0;
	int n;
	cin >> n;
	a[0].left = nullptr;
	a[0].right = &a[1];
	a[1].left = &a[0];
	a[1].right = nullptr;
	a[1].x = 1;
	for (int i = 2; i <= n; i++) {
		cin >> k[i] >> p[i];
	}
	int m;
	cin >> m;
	for (int i = 1; i <= m; i++) {
		int x;
		cin >> x;
		v[x] = 1;
	}
	for (int i = 2; i <= n; i++) {
		//if (v[i]) continue;
		a[i].right = nullptr;
		a[i].x = i;
		if (p[i] == 0) {
			a[i].left = a[k[i]].left;
			a[i].right = &a[k[i]];
			a[k[i]].left->right = &a[i];
			a[k[i]].left = &a[i];
		} else {
			if (a[k[i]].right != nullptr ) a[i].right = a[k[i]].right;
			a[i].left = &a[k[i]];
			if (a[k[i]].right != nullptr ) a[k[i]].right->left = &a[i];
			a[k[i]].right = &a[i];

		}


	}
	for(int i=1;i<=n;i++){
		if(v[i]){
			a[i].left->right=a[i].right;
			if(a[i].right!=nullptr) a[i].right->left=a[i].left;
		}
	}
	int i = 0;
	for (; a[i].right != nullptr; i = a[i].right->x) {
	//	if (a[i].x != 0) {
			if (a[i].right != nullptr) cout << a[i].right->x << " ";
			else cout << "nullptr ";
//		}
	}
//	cout << a[i].x;
	return 0;
}
